<template>
    <el-container>
        <el-header>
            <img src="../assets/imgs/10007 (1).png" alt="">
        </el-header>
        <el-container>
            <el-aside :width="isCollapse?'64px':'200px'">
                <el-menu background-color="#1E1E20" text-color="#fff" active-text-color="#ffd04b" :unique-opened="true" :router="true" :default-active="activeNav" :collapse="isCollapse" :collapse-transition="false">
                    <el-submenu :index="item.id+''" v-for="(item,index) in MenuList" :key="item.id" >
                        <!-- 一级菜单 -->
                        <template slot="title">
                        <i :class="icons[item.id]"></i>
                        <span>{{item.authName}}</span>
                        </template>
                            <!-- 二级菜单 -->
                            <el-menu-item :index="'/'+sonItem.path" v-for="(sonItem,index) in item.children" :key="sonItem.id" @click="navigation('/'+sonItem.path)" >
                                <template slot="title" class="itemContent">
                                    <i class="el-icon-menu"></i>
                                    <span>{{sonItem.authName}}</span>
                                </template>
                            </el-menu-item>
                    </el-submenu>
                </el-menu>
            </el-aside>
            <el-container>
            <el-main>
                <router-view></router-view>
            </el-main>
            <el-footer>
                <img src="../assets/imgs/10010 (1).png" alt="" @click="toggle">
            </el-footer>
            </el-container>
        </el-container>
    </el-container>
</template>
<script>

    export default{
        data(){
            return{
                MenuList:{},
                icons:{
                    '125':'iconfont icon-user',
                    '103':'iconfont icon-tijikongjian',
                    '101':'iconfont icon-shangpin',
                    '102':'iconfont icon-danju',
                    '145':'iconfont icon-baobiao',
                },
                isCollapse:false,
                activeNav:''
            }
        },
        created(){
            this.getMenuList()
            this.activeNav=window.sessionStorage.getItem('nav')
        },
        // vue生命周期属性
        
        methods:{
            async getMenuList(){
                var {data:result}=await this.$http.get('menus')
                if(result.meta.status!==200){return this.$message.error(result.meta.msg)}
                else{
                    this.$message.success(result.meta.msg)
                    this.MenuList=result.data
                }
            },
            toggle(){
                this.isCollapse=!this.isCollapse
            },
            navigation(navPath){
                this.activeNav=navPath
                window.sessionStorage.setItem('nav',navPath)
            }
        }
    }
</script>
<style lang="less" scoped>
.el-container{
    height: 100%;
    .el-header{
        background-color: #1E1E20;
        display: flex;
        align-items: center;
    }
    .el-aside{
        background-color: #1E1E20;
        .el-menu{
            border-right: none;
        }
    }
    .el-main{
        background: url(../assets/imgs/10006.jpg) no-repeat;
        background-size: cover;
        padding: 0;
    }
    .el-footer{
        background-color: #1E1E20;
        display: flex;
        align-items: center;
        box-sizing: border-box;
    }
    .itemContent{
        display: flex;
        align-items: center;
    }
    .iconfont{
        margin-right: 10px;
    }
}
</style>