<template>
    <div class="container">
        <div class="login">
            <!-- 头像 -->
            <div class="avatar">
                <img src="../assets/imgs/logo.png" alt="">
            </div>
            <!-- 表单 -->
            <el-form ref="loginFormRef" :model="loginForm" :rules="rules" label-width="0px" class="login_form">
                <el-form-item prop="username">
                    <el-input placeholder="请输入账号" prefix-icon="iconfont icon-user" v-model="loginForm.username"></el-input>
                </el-form-item>
                <el-form-item prop="password">
                    <el-input placeholder="请输入密码" prefix-icon="iconfont icon-3702mima" type="password" v-model="loginForm.password"></el-input>
                </el-form-item>
                <el-form-item class="buttons">
                    <el-button type="primary" @click="login_verify">登录</el-button>
                    <el-button @click="resetInfo">重置</el-button>
                </el-form-item>
            </el-form>
        </div>
    </div>
</template>

<script>
export default{
    data(){
        return{
            loginForm:{
                username:'admin',
                password:'123456'
            },
            rules:{
                username:[
                    { required: true, message: '用户名为必填项', trigger: 'blur' },
                    { min: 3, max: 8, message: '长度在 3 到 5 个字符', trigger: 'blur' }
                ],
                password:[
                    { required: true, message: '密码为必填项', trigger: 'blur' },
                    { min: 6, max: 12, message: '长度在 6 到 12 个字符', trigger: 'blur' }
                ]
            }
        }
    },
    methods:{
        resetInfo(){
            this.$refs.loginFormRef.resetFields()
        },
        login_verify(valid){
            this.$refs.loginFormRef.validate(async(valid)=>{
                if(!valid) return
                else{
                    // const result=await this.$http.post('login',this.loginForm)
                    // console.log(result.data);
                    const {data:result}=await this.$http.post('login',this.loginForm)
                    if(result.meta.status!==200){return this.$message.error(result.meta.msg);}
                    else{this.$message.success(result.meta.msg);}
                    // 保存token字符串
                    window.sessionStorage.setItem('token',result.data.token)
                    this.$router.push('home')
                }
            })
        }
    }
}
</script>

<style lang="less" scoped>
.container{
    height: 100%;
    width: 100%;
    background-color: #2b4b6b;
    display: flex;
    justify-content: center;
    align-items: center;
    .login{
    width: 450px;
    height: 350px;
    border-radius: 10px;
    border: 6px solid #ddd;
    background-color: #fff;
    box-shadow: 0 0 10px #eee;
    filter: brightness(90%);
    position: relative;
    .avatar{
        width: 130px;
        height: 130px;
        padding: 10px;
        border: 1px solid #eee;
        border-radius: 50%;
        box-shadow: 0 0 10px #ddd;
        position: absolute;
        left: 50%;
        transform: translate(-50%,-40%);
        background:linear-gradient(to bottom, lightblue,skyblue) ;
        img{
            width: 100%;
            height: 100%;
            border-radius: 50%;
            background-color: #ddd;
        }
    }
}
}
.login_form{
    padding:120px 50px 10px 50px;
    display: flex;
    flex-direction: column;
    justify-content: center;
    .buttons{
    display: flex;
    justify-content: center;
}
}
</style>